import React, { useState, useEffect, useCallback } from "react";

import "./DisplayRows.css";



const ParameterDisplay = ({ parameters, isActive, onPageChange, onFocusChange, activeFocus, setAutoModeExternal }) => {

  const [data, setData] = useState({});

  const [autoMode, setAutoMode] = useState(false);

  const [activeIndex, setActiveIndex] = useState(0);



  // Replace modern "optional chaining" with old-style checks

  useEffect(() => {

    if (activeFocus !== undefined && activeFocus !== null && activeFocus >= 0 && activeFocus < parameters.length) {

      setActiveIndex(activeFocus);

    }

  }, [activeFocus, parameters.length]);



  const fetchParameters = useCallback(async () => {

    try {

      const response = await fetch('/parameters.json');

      if (!response.ok) return;

      const jsonArray = await response.json();



      // Use standard .find() but avoid any => { return } shorthand that might confuse old compilers

      const pageData = jsonArray.find(function(obj) { return obj.page !== undefined; });

      if (pageData && onPageChange) onPageChange(pageData.page);



      const focusData = jsonArray.find(function(obj) { return obj.focus !== undefined; });

      if (focusData && onFocusChange) onFocusChange(focusData.focus);



      const autoModeEntry = jsonArray.find(function(obj) { return obj.autoMode !== undefined; });

      if (autoModeEntry !== undefined) {

        setAutoMode(autoModeEntry.autoMode);

        setAutoModeExternal(autoModeEntry.autoMode);

      }



      var formattedData = {};

      jsonArray.forEach(function(item) { 

        if (item.key) { formattedData[item.key] = item.value; }

      });

      setData(formattedData);

    } catch (e) { console.error(e); }

  }, [onPageChange, onFocusChange, setAutoModeExternal]);



  useEffect(() => {

    fetchParameters();

    var id = setInterval(fetchParameters, 200);

    return () => clearInterval(id);

  }, [fetchParameters]);



  // Avoid the modern ternary nested logic if possible

  if (autoMode) {

    return (

      <div className="parameter-rows-wrapper">

        <div className="autonomous-mode-overlay"><h2>AUTONOMOUS MODE ACTIVE</h2></div>

      </div>

    );

  }



  return (

    <div className="parameter-rows-wrapper">

      {parameters.map((param, index) => {

        var val = data[param.key];

        var displayValue = (val !== undefined) ? val : "---";

        var isFocused = (index === activeIndex);

        return (

          <div key={param.key} className={"parameter-row " + (isFocused ? "focused" : "")}>

            <div className="parameter-label">{param.label}</div>

            <div className="parameter-value">{displayValue}</div>

          </div>

        );

      })}

    </div>

  );

};



export default ParameterDisplay;
